import React, { useState, useEffect, useCallback } from 'react';
import { 
    Container, Row, Col, Card, Badge, Button, Modal, 
    Form, Table, Spinner, Alert, InputGroup, ButtonGroup
} from 'react-bootstrap';
import { pedidosService, mesasService } from '../../services/api';
import toast from 'react-hot-toast';

const CuentasPendientes = () => {
    const [mesasConCuentas, setMesasConCuentas] = useState([]);
    const [loading, setLoading] = useState(true);
    const [showPagoModal, setShowPagoModal] = useState(false);
    const [cuentaSeleccionada, setCuentaSeleccionada] = useState(null);
    const [metodoPago, setMetodoPago] = useState('efectivo');
    const [montoRecibido, setMontoRecibido] = useState('');
    const [observacionesPago, setObservacionesPago] = useState('');
    const [procesandoPago, setProcesandoPago] = useState(false);
    const [filtroMonto, setFiltroMonto] = useState('todos'); // 'todos', 'menores', 'mayores'
    const [estadisticas, setEstadisticas] = useState({
        total_mesas: 0,
        total_a_cobrar: 0,
        promedio_cuenta: 0,
        mesa_mayor: null
    });

    const fetchMesasConCuentas = useCallback(async () => {
        try {
            // Obtener todas las mesas con estado 'cuenta_solicitada' o 'ocupada' con pedidos entregados
            const mesasResponse = await mesasService.getAll();
            const mesasPendientes = mesasResponse.data.data.filter(mesa => 
                mesa.estado === 'cuenta_solicitada' || mesa.estado === 'ocupada'
            );

            const mesasConCuentasData = [];

            for (const mesa of mesasPendientes) {
                try {
                    const cuentaResponse = await pedidosService.getCuenta(mesa.id);
                    if (cuentaResponse.data.success) {
                        mesasConCuentasData.push({
                            mesa,
                            cuenta: cuentaResponse.data.data
                        });
                    }
                } catch (error) {
                    // Mesa sin pedidos pendientes, continuar
                    console.log(`Mesa ${mesa.numero} sin cuenta pendiente`);
                }
            }

            // Aplicar filtros
            let mesasFiltradas = mesasConCuentasData;
            if (filtroMonto === 'menores') {
                mesasFiltradas = mesasConCuentasData.filter(item => 
                    parseFloat(item.cuenta.resumen.total_general) <= 50
                );
            } else if (filtroMonto === 'mayores') {
                mesasFiltradas = mesasConCuentasData.filter(item => 
                    parseFloat(item.cuenta.resumen.total_general) > 50
                );
            }

            setMesasConCuentas(mesasFiltradas);

            // Calcular estadísticas
            if (mesasConCuentasData.length > 0) {
                const totales = mesasConCuentasData.map(item => 
                    parseFloat(item.cuenta.resumen.total_general)
                );
                const totalACobrar = totales.reduce((sum, total) => sum + total, 0);
                const promedio = totalACobrar / totales.length;
                const mesaMayor = mesasConCuentasData.reduce((max, item) => 
                    parseFloat(item.cuenta.resumen.total_general) > parseFloat(max.cuenta.resumen.total_general) 
                        ? item : max
                );

                setEstadisticas({
                    total_mesas: mesasConCuentasData.length,
                    total_a_cobrar: totalACobrar,
                    promedio_cuenta: promedio,
                    mesa_mayor: mesaMayor
                });
            } else {
                setEstadisticas({
                    total_mesas: 0,
                    total_a_cobrar: 0,
                    promedio_cuenta: 0,
                    mesa_mayor: null
                });
            }

        } catch (error) {
            console.error('Error fetching mesas con cuentas:', error);
            toast.error('Error al cargar las cuentas pendientes');
        } finally {
            setLoading(false);
        }
    }, [filtroMonto]);

    useEffect(() => {
        fetchMesasConCuentas();
        
        // Auto-refresh cada 30 segundos
        const interval = setInterval(fetchMesasConCuentas, 30000);
        return () => clearInterval(interval);
    }, [fetchMesasConCuentas]);

    const handleAbrirModalPago = useCallback((mesaConCuenta) => {
        setCuentaSeleccionada(mesaConCuenta);
        setMontoRecibido(mesaConCuenta.cuenta.resumen.total_general.toString());
        setMetodoPago('efectivo');
        setObservacionesPago('');
        setShowPagoModal(true);
    }, []);

    const handleProcesarPago = useCallback(async () => {
        if (!cuentaSeleccionada) return;

        const totalCuenta = parseFloat(cuentaSeleccionada.cuenta.resumen.total_general);
        const montoRec = parseFloat(montoRecibido) || 0;

        if (metodoPago === 'efectivo' && montoRec < totalCuenta) {
            toast.error('El monto recibido debe ser mayor o igual al total de la cuenta');
            return;
        }

        setProcesandoPago(true);
        try {
            await pedidosService.procesarPago(cuentaSeleccionada.mesa.id, {
                metodo_pago: metodoPago,
                monto_recibido: metodoPago === 'efectivo' ? montoRec : totalCuenta,
                observaciones_pago: observacionesPago
            });

            const cambio = metodoPago === 'efectivo' ? montoRec - totalCuenta : 0;
            
            toast.success(
                `Pago procesado exitosamente. ${cambio > 0 ? `Cambio: ${cambio.toFixed(2)}` : ''}`,
                { duration: 6000 }
            );

            setShowPagoModal(false);
            fetchMesasConCuentas();
        } catch (error) {
            console.error('Error processing payment:', error);
            const errorMessage = error.response?.data?.error || 'Error al procesar el pago';
            toast.error(errorMessage);
        } finally {
            setProcesandoPago(false);
        }
    }, [cuentaSeleccionada, metodoPago, montoRecibido, observacionesPago, fetchMesasConCuentas]);

    const calcularCambio = useCallback(() => {
        if (!cuentaSeleccionada || metodoPago !== 'efectivo') return 0;
        
        const total = parseFloat(cuentaSeleccionada.cuenta.resumen.total_general);
        const recibido = parseFloat(montoRecibido) || 0;
        return Math.max(0, recibido - total);
    }, [cuentaSeleccionada, metodoPago, montoRecibido]);

    const generarMontosSugeridos = useCallback(() => {
        if (!cuentaSeleccionada) return [];
        
        const total = parseFloat(cuentaSeleccionada.cuenta.resumen.total_general);
        const montos = [];
        
        // Redondear hacia arriba a múltiplos de 5, 10, 20
        const opciones = [5, 10, 20, 50];
        opciones.forEach(multiplo => {
            const monto = Math.ceil(total / multiplo) * multiplo;
            if (monto >= total && !montos.includes(monto)) {
                montos.push(monto);
            }
        });
        
        return montos.slice(0, 4); // Máximo 4 sugerencias
    }, [cuentaSeleccionada]);

    if (loading) {
        return (
            <Container>
                <div className="text-center py-5">
                    <Spinner animation="border" variant="success" size="lg" />
                    <p className="mt-3 h5">Cargando cuentas pendientes...</p>
                </div>
            </Container>
        );
    }

    return (
        <Container fluid>
            {/* Header */}
            <Row className="mb-4">
                <Col>
                    <div className="d-flex justify-content-between align-items-center mb-3">
                        <div>
                            <h2 className="mb-1">
                                <i className="fas fa-cash-register text-success me-2"></i>
                                Cuentas por Cobrar
                            </h2>
                            <p className="text-muted mb-0">
                                Procesa los pagos de las mesas
                            </p>
                        </div>
                        
                        <div className="d-flex gap-2">
                            <ButtonGroup size="sm">
                                <Button 
                                    variant={filtroMonto === 'todos' ? 'primary' : 'outline-primary'}
                                    onClick={() => setFiltroMonto('todos')}
                                >
                                    Todas
                                </Button>
                                <Button 
                                    variant={filtroMonto === 'menores' ? 'primary' : 'outline-primary'}
                                    onClick={() => setFiltroMonto('menores')}
                                >
                                    ≤ $50
                                </Button>
                                <Button 
                                    variant={filtroMonto === 'mayores' ? 'primary' : 'outline-primary'}
                                    onClick={() => setFiltroMonto('mayores')}
                                >
                                    > $50
                                </Button>
                            </ButtonGroup>
                            
                            <Button 
                                variant="outline-info" 
                                size="sm"
                                onClick={fetchMesasConCuentas}
                            >
                                <i className="fas fa-sync-alt me-1"></i>
                                Actualizar
                            </Button>
                        </div>
                    </div>

                    {/* Estadísticas */}
                    <Row>
                        <Col md={3}>
                            <Card className="border-0 shadow-sm bg-primary bg-opacity-10">
                                <Card.Body className="text-center py-3">
                                    <i className="fas fa-table fa-2x text-primary mb-2"></i>
                                    <div className="h3 mb-0 text-primary">{estadisticas.total_mesas}</div>
                                    <div className="small text-muted">Mesas Pendientes</div>
                                </Card.Body>
                            </Card>
                        </Col>
                        <Col md={3}>
                            <Card className="border-0 shadow-sm bg-success bg-opacity-10">
                                <Card.Body className="text-center py-3">
                                    <i className="fas fa-dollar-sign fa-2x text-success mb-2"></i>
                                    <div className="h3 mb-0 text-success">
                                        ${estadisticas.total_a_cobrar.toFixed(2)}
                                    </div>
                                    <div className="small text-muted">Total a Cobrar</div>
                                </Card.Body>
                            </Card>
                        </Col>
                        <Col md={3}>
                            <Card className="border-0 shadow-sm bg-info bg-opacity-10">
                                <Card.Body className="text-center py-3">
                                    <i className="fas fa-chart-line fa-2x text-info mb-2"></i>
                                    <div className="h3 mb-0 text-info">
                                        ${estadisticas.promedio_cuenta.toFixed(2)}
                                    </div>
                                    <div className="small text-muted">Promedio por Mesa</div>
                                </Card.Body>
                            </Card>
                        </Col>
                        <Col md={3}>
                            <Card className="border-0 shadow-sm bg-warning bg-opacity-10">
                                <Card.Body className="text-center py-3">
                                    <i className="fas fa-crown fa-2x text-warning mb-2"></i>
                                    <div className="h3 mb-0 text-warning">
                                        {estadisticas.mesa_mayor ? 
                                            `Mesa ${estadisticas.mesa_mayor.mesa.numero}` : 
                                            'N/A'
                                        }
                                    </div>
                                    <div className="small text-muted">Cuenta Mayor</div>
                                </Card.Body>
                            </Card>
                        </Col>
                    </Row>
                </Col>
            </Row>

            {/* Lista de cuentas */}
            {mesasConCuentas.length === 0 ? (
                <Row>
                    <Col>
                        <Card className="border-0 shadow-sm">
                            <Card.Body className="text-center py-5">
                                <i className="fas fa-credit-card fa-4x text-muted mb-4"></i>
                                <h4>¡Todo cobrado! 💰</h4>
                                <p className="text-muted mb-0">
                                    No hay cuentas pendientes por cobrar.
                                </p>
                            </Card.Body>
                        </Card>
                    </Col>
                </Row>
            ) : (
                <Row>
                    {mesasConCuentas.map(({ mesa, cuenta }) => (
                        <Col lg={4} md={6} key={mesa.id} className="mb-4">
                            <Card className="h-100 border-0 shadow-sm border-success border-2">
                                <Card.Header className="bg-success text-white">
                                    <div className="d-flex justify-content-between align-items-center">
                                        <div>
                                            <h5 className="mb-0">
                                                <i className="fas fa-table me-2"></i>
                                                Mesa {mesa.numero}
                                            </h5>
                                            <small className="opacity-75">
                                                {mesa.capacidad} personas • {cuenta.resumen.total_pedidos} pedidos
                                            </small>
                                        </div>
                                        <Badge bg="light" text="dark" className="px-2 py-1">
                                            {cuenta.resumen.total_items} items
                                        </Badge>
                                    </div>
                                </Card.Header>

                                <Card.Body>
                                    <div className="mb-3">
                                        <strong className="text-muted small">RESUMEN DE CONSUMO:</strong>
                                        <div className="bg-light p-3 rounded mt-2" style={{ maxHeight: '200px', overflowY: 'auto' }}>
                                            {cuenta.resumen.productos.map((producto, index) => (
                                                <div key={index} className="d-flex justify-content-between align-items-center mb-1">
                                                    <div>
                                                        <strong>{producto.cantidad}x</strong>{' '}
                                                        <span>{producto.producto.nombre}</span>
                                                    </div>
                                                    <span className="text-success fw-bold">
                                                        ${parseFloat(producto.subtotal).toFixed(2)}
                                                    </span>
                                                </div>
                                            ))}
                                        </div>
                                    </div>

                                    <div className="border-top pt-3">
                                        <div className="d-flex justify-content-between align-items-center mb-3">
                                            <h4 className="mb-0">TOTAL:</h4>
                                            <h3 className="mb-0 text-success">
                                                ${parseFloat(cuenta.resumen.total_general).toFixed(2)}
                                            </h3>
                                        </div>

                                        <div className="text-center">
                                            <small className="text-muted">
                                                Generada: {new Date(cuenta.fecha_generacion).toLocaleString()}
                                            </small>
                                        </div>
                                    </div>
                                </Card.Body>

                                <Card.Footer className="bg-white border-0">
                                    <div className="d-grid">
                                        <Button
                                            variant="success"
                                            size="lg"
                                            className="fw-bold"
                                            onClick={() => handleAbrirModalPago({ mesa, cuenta })}
                                        >
                                            <i className="fas fa-credit-card me-2"></i>
                                            Procesar Pago
                                        </Button>
                                    </div>
                                </Card.Footer>
                            </Card>
                        </Col>
                    ))}
                </Row>
            )}

            {/* Modal de procesamiento de pago */}
            <Modal show={showPagoModal} onHide={() => setShowPagoModal(false)} size="lg" centered>
                <Modal.Header closeButton>
                    <Modal.Title>
                        <i className="fas fa-credit-card me-2"></i>
                        Procesar Pago - Mesa {cuentaSeleccionada?.mesa.numero}
                    </Modal.Title>
                </Modal.Header>
                <Modal.Body>
                    {cuentaSeleccionada && (
                        <>
                            {/* Resumen de la cuenta */}
                            <div className="bg-light p-3 rounded mb-4">
                                <Row>
                                    <Col md={6}>
                                        <div className="mb-2">
                                            <strong>Mesa:</strong> {cuentaSeleccionada.mesa.numero}
                                        </div>
                                        <div className="mb-2">
                                            <strong>Items:</strong> {cuentaSeleccionada.cuenta.resumen.total_items}
                                        </div>
                                    </Col>
                                    <Col md={6}>
                                        <div className="mb-2">
                                            <strong>Pedidos:</strong> {cuentaSeleccionada.cuenta.resumen.total_pedidos}
                                        </div>
                                        <div className="mb-2">
                                            <strong className="h5 text-success">
                                                Total: ${parseFloat(cuentaSeleccionada.cuenta.resumen.total_general).toFixed(2)}
                                            </strong>
                                        </div>
                                    </Col>
                                </Row>
                            </div>

                            {/* Método de pago */}
                            <Form.Group className="mb-3">
                                <Form.Label className="fw-bold">Método de Pago</Form.Label>
                                <div className="d-flex gap-2">
                                    <Button
                                        variant={metodoPago === 'efectivo' ? 'success' : 'outline-success'}
                                        onClick={() => setMetodoPago('efectivo')}
                                        className="flex-fill"
                                    >
                                        <i className="fas fa-money-bill-wave me-2"></i>
                                        Efectivo
                                    </Button>
                                    <Button
                                        variant={metodoPago === 'tarjeta' ? 'success' : 'outline-success'}
                                        onClick={() => setMetodoPago('tarjeta')}
                                        className="flex-fill"
                                    >
                                        <i className="fas fa-credit-card me-2"></i>
                                        Tarjeta
                                    </Button>
                                    <Button
                                        variant={metodoPago === 'transferencia' ? 'success' : 'outline-success'}
                                        onClick={() => setMetodoPago('transferencia')}
                                        className="flex-fill"
                                    >
                                        <i className="fas fa-mobile-alt me-2"></i>
                                        Transferencia
                                    </Button>
                                </div>
                            </Form.Group>

                            {/* Monto recibido (solo para efectivo) */}
                            {metodoPago === 'efectivo' && (
                                <Form.Group className="mb-3">
                                    <Form.Label className="fw-bold">Monto Recibido</Form.Label>
                                    <InputGroup>
                                        <InputGroup.Text>$</InputGroup.Text>
                                        <Form.Control
                                            type="number"
                                            step="0.01"
                                            value={montoRecibido}
                                            onChange={(e) => setMontoRecibido(e.target.value)}
                                            placeholder="0.00"
                                        />
                                    </InputGroup>
                                    
                                    {/* Montos sugeridos */}
                                    <div className="mt-2">
                                        <small className="text-muted">Montos sugeridos:</small>
                                        <div className="d-flex gap-1 mt-1">
                                            {generarMontosSugeridos().map(monto => (
                                                <Button
                                                    key={monto}
                                                    variant="outline-secondary"
                                                    size="sm"
                                                    onClick={() => setMontoRecibido(monto.toString())}
                                                >
                                                    ${monto}
                                                </Button>
                                            ))}
                                        </div>
                                    </div>
                                    
                                    {/* Cambio */}
                                    {calcularCambio() > 0 && (
                                        <Alert variant="info" className="mt-3 mb-0">
                                            <div className="d-flex justify-content-between align-items-center">
                                                <strong>Cambio a entregar:</strong>
                                                <span className="h5 mb-0">${calcularCambio().toFixed(2)}</span>
                                            </div>
                                        </Alert>
                                    )}
                                </Form.Group>
                            )}

                            {/* Observaciones */}
                            <Form.Group className="mb-3">
                                <Form.Label>Observaciones del Pago</Form.Label>
                                <Form.Control
                                    as="textarea"
                                    rows={2}
                                    value={observacionesPago}
                                    onChange={(e) => setObservacionesPago(e.target.value)}
                                    placeholder="Opcional - notas sobre el pago..."
                                />
                            </Form.Group>
                        </>
                    )}
                </Modal.Body>
                <Modal.Footer>
                    <Button variant="secondary" onClick={() => setShowPagoModal(false)}>
                        Cancelar
                    </Button>
                    <Button 
                        variant="success" 
                        size="lg"
                        onClick={handleProcesarPago}
                        disabled={
                            procesandoPago || 
                            (metodoPago === 'efectivo' && parseFloat(montoRecibido) < parseFloat(cuentaSeleccionada?.cuenta.resumen.total_general || 0))
                        }
                    >
                        {procesandoPago ? (
                            <>
                                <Spinner animation="border" size="sm" className="me-2" />
                                Procesando...
                            </>
                        ) : (
                            <>
                                <i className="fas fa-check me-2"></i>
                                Confirmar Pago ${cuentaSeleccionada?.cuenta.resumen.total_general}
                            </>
                        )}
                    </Button>
                </Modal.Footer>
            </Modal>
        </Container>
    );
};

export default CuentasPendientes;
